import { getTranslations } from "next-intl/server";
import { AppShell } from "@/components/app-shell";
import { BoardForm } from "@/components/board/board-form";
import { getAuthContext } from "@/lib/firebase/auth";
import { boardsRepository } from "@/lib/repositories/boards-repository";

export default async function Page() {
  const common = await getTranslations("Common");
  const t = await getTranslations("Board");
  const auth = await getAuthContext();
  if (!auth?.workspaceId) {
    return <AppShell section="board"><p>{common("unauthenticated")}</p></AppShell>;
  }

  const boards = await boardsRepository.list(auth.workspaceId);

  return (
    <AppShell section="board">
      <div className="content-stack space-y-6">
        <section className="app-card"><BoardForm /></section>
        <section className="list-grid">
          {boards.map((board) => (
            <article key={board.id} className="list-card">
              <div className="list-card-header">
                <div>
                  <h2 className="font-semibold">{board.title}</h2>
                  <p className="text-sm muted">{board.description || t("noDescription")}</p>
                </div>
                <span className="tag-pill">{t("title")}</span>
              </div>
            </article>
          ))}
          {boards.length === 0 ? <p className="empty-state">{t("empty")}</p> : null}
        </section>
      </div>
    </AppShell>
  );
}
