import Link from "next/link";
import { ReactNode } from "react";
import { BookOpen, Kanban, LayoutDashboard, Sparkles, User, Users } from "lucide-react";
import { getTranslations } from "next-intl/server";
import { SignOutButton } from "@/components/sign-out-button";

type AppSection = "dashboard" | "board" | "knowledge" | "skills" | "team" | "profile" | "knowledgeDetail" | "skillDetail";

const items = [
  { href: "/dashboard", key: "dashboard", icon: LayoutDashboard },
  { href: "/board", key: "board", icon: Kanban },
  { href: "/knowledge", key: "knowledge", icon: BookOpen },
  { href: "/skills", key: "skills", icon: Sparkles },
  { href: "/team", key: "team", icon: Users },
] as const;

const sectionTitleKey: Record<AppSection, string> = {
  dashboard: "Dashboard.title",
  board: "Board.title",
  knowledge: "Knowledge.title",
  skills: "Skills.title",
  team: "Team.title",
  profile: "Profile.title",
  knowledgeDetail: "Knowledge.detailTitle",
  skillDetail: "Skills.detailTitle",
};

export async function AppShell({ section, children }: { section: AppSection; children: ReactNode }) {
  const shell = await getTranslations("Shell");
  const titles = await getTranslations();
  const title = titles(sectionTitleKey[section]);

  return (
    <div className="app-layout">
      <aside className="app-sidebar">
        <Link href="/dashboard" className="app-brand">
          <span className="app-brand-mark">TK</span>
          <span>{shell("brand")}</span>
        </Link>

        <div className="workspace-switcher">
          <span className="workspace-icon">A</span>
          <div>
            <p>Acme</p>
            <span>{shell("workspaceActive")}</span>
          </div>
        </div>

        <nav className="sidebar-nav">
          {items.map((item) => {
            const Icon = item.icon;
            return (
              <Link key={item.href} href={item.href} className={section === item.key ? "active" : undefined}>
                <span aria-hidden="true"><Icon size={16} strokeWidth={2.4} /></span>
                <strong>{shell(`nav.${item.key}`)}</strong>
              </Link>
            );
          })}
        </nav>

        <div className="sidebar-footer">
          <Link href="/profile" className={section === "profile" ? "active" : undefined}>
            <span aria-hidden="true"><User size={16} strokeWidth={2.4} /></span>
            <strong>{shell("nav.profile")}</strong>
          </Link>
          <SignOutButton />
        </div>
      </aside>

      <main className="app-main">
        <header className="app-page-header">
          <div>
            <p className="eyebrow">{shell("workspaceEyebrow")}</p>
            <h1>{title}</h1>
          </div>
        </header>
        {children}
      </main>
    </div>
  );
}
